import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface SegmentSplit {
  segment: string;
  time: string;
}

interface RunningStatsData {
  currentRun: {
    pace: string;
    distance: string;
    elevationGain: string;
  };
  segmentSplits: SegmentSplit[];
}

export default function Widget() {
  const runningData = response.data as RunningStatsData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722' }}>
              Current Run
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Pace: {runningData.currentRun.pace}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Distance: {runningData.currentRun.distance}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Elevation Gain: {runningData.currentRun.elevationGain}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: runningData.segmentSplits.map(split => parseFloat(split.time.replace(':', '.'))),
                  color: '#4CAF50',
                  label: 'Segment Time',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: runningData.segmentSplits.map(split => split.segment),
                  id: 'segments',
                },
              ]}
              yAxis={[{ id: 'time' }]}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="segments"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
